mapper.select:
select id, user_id, auth_type, auth_key, credential, verified, create_time, update_time
from user_auth
where auth_type = #{authType}
  and auth_key = #{authKey}
limit 1;

select id, user_id, auth_type, auth_key, credential, verified, create_time, update_time
from user_auth
where user_id = #{userId};

mapper.delete:
delete from user_auth
where auth_type = #{authType}
  and user_id = #{userId}
